import { SelectableValue, StandardEditorProps } from '@grafana/data';
import { Select } from '@grafana/ui';
import React, { useEffect, useState } from 'react';
import { CameraResponse } from 'types/Camera';

export const SimpleEditor: React.FC<StandardEditorProps<string>> = ({ item, value, onChange }) => {
  const [options, setOptions] = useState<Array<SelectableValue<string>>>([]);

  useEffect(() => {
    fetch('/visionapi/cameras')
      .then((response) => response.json())
      .then((json: CameraResponse) => {
        const cameras = json.rows.map((camera) => {
          return {
            label: camera.name,
            value: camera.name,
          };
        });
        setOptions(cameras);
      })
      .catch(() => {
        setOptions([]);
      });
  }, []);

  return <Select options={options} value={value} onChange={(selectableValue) => onChange(selectableValue.value)} />;
};
